import React, { useCallback } from "react";

export const useHttp = () => {
  useCallback(async function http(params) {
    try {
      await fetch("http://localhost:5000", {
        method: "get",
      })
        .then((response) => response.json())
        .then((result) => console.log(result));
    } catch (error) {
      console.log(error);
    }
  }, []);
};
